const express = require('express');
const http = require('http');
const socketIo = require('socket.io');
const session = require('express-session');
const crypto = require('crypto');

const app = express();
const server = http.createServer(app);
const io = socketIo(server);

const sessionMiddleware = session({
  secret: 'your-secure-secret',
  resave: false,
  saveUninitialized: true,
  cookie: { secure: true, httpOnly: true, maxAge: 60000 }
});

app.use(sessionMiddleware);

io.use((socket, next) => {
  sessionMiddleware(socket.request, socket.request.res || {}, next);
});

const users = {}; // Store user sessions

app.post('/login', (req, res) => {
  const { username } = req.body;
  if (!username || typeof username !== 'string') {
    return res.status(400).send('Invalid username');
  }
  const sessionId = crypto.randomBytes(16).toString('hex');
  users[sessionId] = { username, score: 0 };
  req.session.userId = sessionId;
  res.send({ success: true });
});

io.on('connection', (socket) => {
  const sessionId = socket.request.session.userId;
  if (!sessionId || !users[sessionId]) {
    return socket.disconnect(true);
  }

  socket.on('submitScore', (data) => {
    const { score } = data;
    if (typeof score !== 'number' || score < 0) {
      return socket.emit('error', 'Invalid score');
    }
    users[sessionId].score = score;
    socket.emit('scoreUpdated', { score });
  });

  socket.on('disconnect', () => {
    delete users[sessionId];
  });
});

server.listen(3000, () => {
  console.log('Server is running on port 3000');
});